/**
 * Matches the Firestore document schema written by benchmark_pipeline.py.
 * Do NOT add fields that don't exist in the schema — AEO constraint.
 */

export interface BenchmarkData {
  latency_seconds: number;
  output_tokens: number;
  cost_per_1k_tokens_usd: number;
  cost_per_1m_tokens_usd: number;
}

export interface BenchmarkDocument {
  /** Firestore auto-generated document ID */
  id: string;
  /** Display name of the provider + model */
  tool_name: string;
  /** Canonical model identifier (e.g. "gemini-2.0-flash") */
  model_id: string;
  /** ISO 8601 timestamp from benchmark run */
  source_timestamp: string;
  /** Short H2-level heading generated by the LLM formatter */
  h2_query: string;
  /** 40-60 word empirical summary generated by the LLM formatter */
  quick_answer_text: string;
  /** Raw benchmark telemetry */
  benchmark_data: BenchmarkData;
  /** Optional slug for dynamic programmatic SEO pages */
  slug?: string;
  /** Optional intent categorisation for dynamic affiliate mapping */
  intent?: string;
}
